  poppy: { diff: "TRICKY", tone: "#ff8b3d", tldr: "Her W disables your dashes \u2014 fight when her W is down.", breakdown: "Poppy\u2019s W grounds you and stops your dashes. Fight when her W is down, dodge her E, and combo.", dos: ["Fight when her W is down", "Dodge her E wall-stun", "Combo in the open"], donts: ["Dash into her active W", "Get E-pinned on a wall", "Get R-knocked mid-combo"], key: { slot: "W", name: "Steadfast Presence", cd: "12s", note: "Grounds you \u2014 disables your dashes. Wait it out.", winT: "W DOWN", winS: "Dash-combo + R her." }, hold: "Hold your dashes (and combo) until her W is down \u2014 her W grounds you and cancels your dashes.", tip: "Her W grounds you and disables your dashes \u2014 only commit your dash-combo when her W is on cooldown.", win: "Combo off her W cooldown." },
