  tahmkench: { diff: "EVEN", tone: "#e8b84b", tldr: "Dash his tongue \u2014 combo, deny his dive.", breakdown: "Dash out of his Q tongue, weave your combo, and avoid 3 passive stacks.", dos: ["Dash his Q tongue", "Weave your combo", "Avoid 3 passive stacks"], donts: ["Get Q-stunned", "Fight into his W reactivate", "Eat free passive stacks"], key: { slot: "W", name: "Abyssal Dive", cd: "12s", note: "His escape + shield. Combo when down.", winT: "W DOWN", winS: "Dash-combo + R him." }, hold: "Hold your dash for his Q tongue \u2014 dodge the stun, then combo him when his W is down.", tip: "Dash out of his Q tongue, weave your combo, and avoid stacking his passive.", win: "Dash his tongue and combo him." },
  zac: { diff: "EVEN", tone: "#e8b84b", tldr: "Dash his E \u2014 step on blobs, combo him.", breakdown: "Step on his blobs, dash out of his E engage, anti-heal, and dash-combo burst him.", dos: ["Step on his blobs", "Dash his E engage", "Dash-combo burst him"], donts: ["Let him eat blobs", "Get E-knocked-up", "Fight without anti-heal"], key: { slot: "E", name: "Elastic Slingshot", cd: "16s", note: "His engage. Dash it.", winT: "SLINGSHOT DOWN", winS: "Dash-combo + R him." }, hold: "Hold your dash for his E slingshot \u2014 dodge the knockup, then dash-combo burst him.", tip: "Deny his blobs, dash out of his E, anti-heal, and dash-combo burst him.", win: "Dash his E and combo him." },
  // ===== MAGES, MARKSMEN & SPECIALISTS =====
  akali: { diff: "TRICKY", tone: "#ff8b3d", tldr: "Build MR \u2014 fight off her shroud, dash her all-in.", breakdown: "Build MR, dash out of her all-in, and dash-combo her when her shroud + energy are spent.", dos: ["Build MR", "Dash out of her all-in", "Combo when her W is down"], donts: ["Combo into her shroud", "Fight her 6 with no MR", "Get Q-poked down"], key: { slot: "W", name: "Twilight Shroud", cd: "18s", note: "Untargetable inside. Combo when down.", winT: "SHROUD DOWN", winS: "Dash-combo + R her." }, hold: "Hold your dash for her all-in \u2014 dodge her E-Q burst, then combo her off the shroud; build MR.", tip: "Build MR, dash out of her all-in, and dash-combo her when her shroud and energy are spent.", win: "Build MR and combo her off shroud." },
