  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — dash-weave around his Heroic Swing and crash the empowered hits.","breakdown":"Akshan plays around Heroic Swing. Every cast loads an empowered strike — weave dash-resets through his Heroic Swing gap and the R lock finishes the chain. Doran’s Shield blunts the poke war.","dos":["Weave dash-resets into trades","Empowered hit after each cast","R the locked kill"],"donts":["Burn all dashes in","Trade without passive loaded","R into peel"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"Dash-chain + empowered crash."},"win":"Dash-weave around his Heroic Swing and crash the empowered hits."},
  cassiopeia: {"diff":"HARD","tone":"#ff5d6c","tldr":"He kites you out — survive, then dash-weave around his Miasma and crash the empowered hits.","breakdown":"Cassiopeia plays around Miasma. Every cast loads an empowered strike — weave dash-resets through his Miasma gap and the R lock finishes the chain. Take Mercs / MR shard — his damage is magic. Doran’s Shield blunts the poke war.","dos":["Weave dash-resets into trades","Empowered hit after each cast","R the locked kill"],"donts":["Burn all dashes in","Trade without passive loaded","R into peel"],"key":{"slot":"W","name":"Miasma","cd":"12s","note":"Grounds you — dashes and movement abilities are disabled inside it.","winT":"MIASMA DOWN","winS":"Dash-chain + empowered crash."},"win":"Dash-weave around his Miasma and crash the empowered hits."},
